#include<bits/stdc++.h>
using namespace std;
int a[200010];
int main()
{
    int n,k,ans=0;
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=29;i>=0;i--)
    {
        int sum=0,cnt=0;
        int x=(ans+(1<<i));
        for(int j=1;j<=n;j++)
        {
            sum|=a[j];
            if((sum&x)==x)
            {
                sum=0;
            }
            else
            {
                cnt++;
            }
        }
        if(cnt<=k)
        {
            ans+=(1<<i);
        }
    }
    printf("%d",ans);
    return 0;
}
